command.text:

var f = this, g = f.grid, v = g._dateFrom, d = (v.getDay() != 0) ? v.getDay(): 7;
for (var i = 1; i <= 40; i++) {
  var field = 'n' + (i > 9 ? i.toString() : '0' + i.toString()), t;
  t =((i + d - 1) > 42) ? '' : f.getItem('d' + (i + d - 1).toString()).value;
  f.setItemValue(field, t);
}

script.text:

function init$EmployeeShiftScheduleForm(f) {
  f.add_onResponseComplete(on$EmployeeShiftScheduleForm$ResponseComplete);
  var g = f.grid;
  f.setItemValues('tu_ngay, den_ngay', [g._dateFrom, g._dateTo]);
  set$EmployeeShiftScheduleFormLayout(f);
}
function load$EmployeeShiftScheduleForm(f) {
  for (var i = 1; i <= 42; i++) {
    changeLookupReadonly(f, 'd' + i.toString(), true);
  }
  f.setReadOnlyFields('tu_ngay, den_ngay, ma_nv, ma_bp, ma_vi_tri');
  f.live(f.getItem('tu_ngay'));
}
function close$EmployeeShiftScheduleForm(f) {try {f.remove_onResponseComplete(on$EmployeeShiftScheduleForm$ResponseComplete);} catch (ex) {}}
function set$EmployeeShiftScheduleFormLayout(f) {
  var line = '1px solid #c0d1e9', blank = '#f0f4fb', normal = '#ffffff', sunday = '#e9edf1';
  var g = f.grid, d1 = d = g._dateFrom, d2 = g._dateTo;
  var timeDiff = Math.abs(Date.UTC(d2.getFullYear(), d2.getMonth(), d2.getDate()) - Date.UTC(d1.getFullYear(), d1.getMonth(), d1.getDate()));
  var d0 = (d1.getDay() != 0) ? d1.getDay(): 7, d3 = Math.floor(timeDiff / 86400000) + 1, id = f.get_id() + '0_formCell_';
  var sd = [7, 14, 21, 28, 35, 42], m = d1.getMonth();
  var s = f.getItemValue('stt_rec_nv');
  f.request('GetFormData', 'GetFormData', [['datefrom', 'DateTime', f.getItemValue('tu_ngay')], ['dateto', 'DateTime', f.getItemValue('den_ngay')], ['s', 'String', s]]);
  setHeaderStyle(id, line);

  for (var i = 1; i <= 42; i++) {
    var item = 'd' + i.toString(), o = f.getItem(item), cell = $get(item);
    if ((i > d0 - 1) && (i < d3 + d0)) {
      var date = d.getDate(), month = d.getMonth(), v;
      v = d.getFullYear().toString() + convertNumberToString(d.getMonth() + 1).toString() + convertNumberToString(d.getDate()).toString();
      var index = date + ((date == 1 && m != month) ? ('/' + (month + 1).toString()) : ''), k = ((g._nonWorking.indexOf(v) == -1) && (Array.indexOf(sd, i) == -1));
      setCellStyle(o, cell, k ? normal : sunday, index, k);
      d = addDays(d, 1);
    }
    else {disableCellStyle(o, cell, blank, i);}
  }
  setBorderStyle(g, id, line, blank, normal, sunday);
}

function setHeaderStyle(id, line) {
  for (i = 2; i <= 16; i += 2) {
    if (i == 4) i += 2;
    var o = $get(id + '6.' + i.toString()), style = o.style;
    style.borderTop = line;
    style.borderLeft = line;
    style.backgroundColor = '#e6edf7';
    if (i == 16) style.borderRight = line;
    if ($func.isOpr) o.childNodes[0].style.padding = 0;
  }
  $get(id + '6.2').parentNode.style.height = $func.isSr ? '31px' : '27px';
}
function setCellStyle(o, cell, color, index, k) {
  var style = o.style, parentStyle = o.parentNode.style;
  cell.innerHTML = index.toString();
  cell.style.color = '#008ecc';
  cell.style.marginRight = ($func.isOpr) ? '2px' : '6px';

  style.width = $func.isCs ? '68px' : '65px';
  style.paddingLeft = ($func.isSr || $func.isOpr) ? '4px' : '0';
  style.backgroundColor = o.parentNode.parentNode.style.backgroundColor = color;

  parentStyle.marginLeft = ($func.isSr) ? '-7px' : '-5px';
  parentStyle.marginBottom = '6px';
  parentStyle.marginTop = $func.isSr ? '4px' : '0';

  if ($func.isOpr) parentStyle.width = '82px';
  if (k) parentStyle.borderBottom = '1px solid #e6edf7';
}
function disableCellStyle(o, cell, color, index) {
  if (index == 42) {
    cell.innerHTML = '&nbsp;';
    cell.disabled = true;
  }
  var parent = o.parentNode;
  o.disabled = true;
  if (o.a) $common.setVisible(o.a, false);
  cell.style.color = color;
  o.style.backgroundColor = parent.parentNode.style.backgroundColor = color;
  parent.style.borderBottom = 'none';
  parent.style.marginBottom = '7px';
}
function setBorderStyle(g, id, line, blank, normal, sunday) {
  var d = g._dateFrom;
  for (var i = 7; i <= 18; i++) {
    for (var j = 1; j <= 16; j++) {
      if (j == 4) j = 6;

      var o = $get(id + i.toString() + '.' + j.toString()), style = o.style;
      if (i == 7) style.borderTop = line;
      if (j == 16) style.borderRight= line;
      if (i % 2 == 0) style.borderBottom = line;

      if (j % 2 != 0) style.borderLeft = line;
      else {
        var v = o.firstChild.firstChild.innerHTML, c = j - (j == 6 ? 3 : 1), e = c.toString();
        if ((!v) && (o.firstChild.firstChild.id.length <= 15)) {
          style.backgroundColor = blank;
          $get(id + i.toString() + '.' + e).style.backgroundColor = blank;
          $get(id + (i + 1).toString() + '.' + e).style.backgroundColor = blank;
        }

        if (v) {
          var dmy = d.getFullYear().toString() + convertNumberToString(d.getMonth() + 1).toString() + convertNumberToString(d.getDate()).toString();
          d = addDays(d, 1);
          var color = (j != 16 && (g._nonWorking.indexOf(dmy) == -1)) ? normal : sunday;
          if (v == '&nbsp;') color = blank;
          style.backgroundColor = color;
          $get(id + i.toString() + '.' + e).style.backgroundColor = color;
          $get(id + (i + 1).toString() + '.' + e).style.backgroundColor = color;
        }
      } 
    }
  }
}
function on$EmployeeShiftScheduleForm$ResponseComplete(sender, e) {
  var f = e.object, g = f.grid, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'GetFormData':
      var v = g._dateFrom, d = (v.getDay() != 0) ? v.getDay(): 7, i = 0;
      while (i < 40) {
        if ((d + i) <= 42) {f.setItemValue('d' + (d + i).toString(), result[i].Value);}
        i += 1;
      }
      break;
    default:
      break;
  }
}

      &OutlineEntry;
